    $(function() {

        $(document).on('click', '.cats', function(e) {
            e.preventDefault();
            if(/Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent)){

                window.location = $(this).data('link');
            }else{
                $('.cats').removeClass('active');
                $(this).addClass('active');
                getArticles($(this).data('id'));
                $('#menu-cat-title').attr('href',$(this).data('link'));
                $('#menu-cat-title').html('
'+$(this).text()+'');
                $('#menu-cat-link').attr('href',$(this).data('link'));
            }

        });

        $(document).on('click', '.toggle-menu', function(e) {
            e.preventDefault();
            $(this).parent().children('.nav__sub-list-item').slideToggle();
        });
        $(document).on('click', '.open-dropdown', function(e) {
            e.preventDefault();
        });
        $(document).on('click', function (event) {
            if (!$(event.target).closest('.nav').length) {
                $('.nav__sub-list-item').hide();
            }
        });
    });
    function stripHtmlTags(htmlString) {
        if (!htmlString) return '';
        const tempDiv = document.createElement('div');
        tempDiv.innerHTML = htmlString;
        return tempDiv.textContent || tempDiv.innerText || '';
    }
    function getArticles(id) {
        $('#nav-articles').fadeOut();
        $.ajax({
            url: "/hy/news/cat_articles/"+id,
            dataType: "json",
            type: 'GET',
            success: function(response){
                if (response.status === true) {
                    let feed_html = '';
                    const articles = response.articles;

                    if (articles) {
                        $.each(response.articles, function(i, article) {
                            if(i == 3){return false;}
                            if(i==1){
                                feed_html+='
';
                            }
                            if(i==0){
                                var article_html = build_cat_article_menu(article,true);
                            }else{
                                var article_html = build_cat_article_menu(article,false);
                            }
                            feed_html += article_html;
                        });
                        feed_html += '';
                        $('#nav-articles').html(feed_html);
                        $('#nav-articles').fadeIn("slow");
                    }
                } else {

                }
            },
        });
    }
    function build_cat_article_menu(article,first) {
            if(first){
                var html = 
                    `



                            ${article.publish_date}

${article.title}

${article.short_desc}

                    `;

            }else{
                var html = 
                    `

                        ${article.publish_date}

${article.title}

${article.short_desc}


                                    Կարդալ


                    `;
            }
            return html;
        }

section.script:
function stripHtmlTags(htmlString) {
    if (!htmlString) return '';
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = htmlString;
    return tempDiv.textContent || tempDiv.innerText || '';
}
function build_feed_article(article) {
    const html = 
        `




                    ${article.publish_date}




                            ${article.title}








        `;

    return html;
}

function get_feed_articles(url) { 
    $('.feed_infinite_container').addClass('loading_data');
    $.ajax({
        url: url,
        dataType: "json",
        type: 'GET',
        success: function(response){
            if (response.status === true) {
                let feed_html = '';
                const articles = response.articles;
                const next_url = response.next_url ? response.next_url : '';

                $('.feed_infinite_container').attr('data-next-url', next_url);

                if (articles) {
                    $.each(response.articles, function(i, article) {
                        const article_html = build_feed_article(article);
                        feed_html += article_html;
                    });
                    $('.feed_infinite_container').append(feed_html);
                }
                $('.feed_infinite_container').removeClass('loading_data');
                if(window.location.pathname=="/hy/" || window.location.pathname=="/ru/" || window.location.pathname=="/en/"){
                    var controller11 = new ScrollMagic.Controller();
                    var scene11 = new ScrollMagic.Scene({
                        triggerElement: ".header",
                        offset: 0,
                    })
                    .on("enter", function() {
                        $(".feed_infinite_container").addClass("slide-up active"); // Add animation classes
                    })
                    .addTo(controller11);
                }else{
                    $(".feed_infinite_container").removeClass("slide-up");
                }

            } else {

            }
        },
    });
}

function init_feed() {
    const url = "/hy/news/feed/1/";
    get_feed_articles(url);
}

$(function() {
    init_feed();
    var controller12 = new ScrollMagic.Controller();
    var scene12 = new ScrollMagic.Scene({
        triggerElement: ".header",
        offset: 700,
    })
    .on("enter", function() {
        $(".ad_zone_below_feed1").addClass("slide-up active"); // Add animation classes
    })
    .addTo(controller12);
    $('.feed_infinite_container').on('scroll', function() {
        // ignore scroll event while getting data by ajax
        if($('.feed_infinite_container').hasClass('loading_data')) {
            return;
        }

        const url = $('.feed_infinite_container').attr('data-next-url');
        if (!url) {
            return;
        }

        let div = $(this).get(0);
        const articles_height = $(".news_feed_item").height() * 5;
        if(div.scrollTop + div.clientHeight >= div.scrollHeight - articles_height) {
            get_feed_articles(url);
        }
    });
});

window.onload = function() {
    const openFeed = document.querySelector('.feed-mobile-btn');
    const newsBlog = document.querySelector('.news-section__newsblog.news-feed');
    const closeFeed = document.querySelector('.close-feed');
    const hasAnimated = document.querySelectorAll('.hasAnimated');

    openFeed.addEventListener('click', function(e){
        closeFeed.classList.remove('active');
        openFeed.classList.add('active');
        openFeed.classList.add('toggle');
        hasAnimated.forEach(function(el){
            el.classList.remove('fade-out');
            el.classList.add('fade-in');
            el.classList.add('animate');
        });

    });

    closeFeed.addEventListener('click', function(e){
        openFeed.classList.remove('active');
        if(openFeed.classList.contains('toggle')){
            closeFeed.classList.add('active');
            openFeed.classList.remove('toggle');
            hasAnimated.forEach(function(el){
                el.classList.add('fade-out');
                el.classList.remove('fade-in');
                el.classList.remove('animate');
            });
        }
    });

}

