$(function() {
    $(document).on('click', '.dropdown-item', function(e) {
        event.stopPropagation();
        $(this).children('.footer__sub-list-item').slideToggle();
    });
    $(document).on('click', '.open-dropdown', function(e) {
        e.preventDefault();
        $(this).children('.nav__sub-list-item').slideToggle();
    });
    $(document).on('click', function (event) {
        if (!$(event.target).closest('.footer__left-side ul').length) {
            $('.footer__sub-list-item').hide();
        }
    });
});

$( document ).ready(function() {
    $('.tv-nav .open-tv').click(function(){
       $('.open-tv').hide();
       $('.tv-ul').show();
       $('.close-tv').show();
    });

    $('.tv-nav .close-tv').click(function(){
        $('.close-tv').hide();
        $('.open-tv').show();
        $('.tv-ul').hide();
    });
});
function stripHtmlTags(htmlString) {
